internal final class ETGVendInvoiceOpenTransController extends SrsReportRunController
{
}

Method.Source:
/// <summary>
/// Class entry point. The system will call this method when a designated menu 
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
/// 
public static ETGVendInvoiceOpenTransController construct()
{
    return new ETGVendInvoiceOpenTransController();
}

public static void main(Args _args)
{
    ETGVendInvoiceOpenTransController   controller = ETGVendInvoiceOpenTransController::construct();
    ETGCanadaParameters         canadaParameters   = ETGCanadaParameters::find();

    if(canadaParameters.ETGAPNotifications == NoYes::Yes)
    {
        controller.parmReportName(ssrsReportStr(ETGVendInvoiceOpenTransReport, Report));
        controller.parmArgs(_args);
        controller.parmDialogCaption("@ETGInvoiceDueNotification:ETGIDN009");
        controller.startOperation();
    }

    else
    {
        warning("@ETGInvoiceDueNotification:ETGIDN013");
    }
}
